import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; public class PwdCheck { public static void main(String[] args) { BCryptPasswordEncoder e = new BCryptPasswordEncoder(); String hash = "$2a$10$N.zmdr9k7uOCQb376NoUnuTJ8iAt6Z5EHsM8lE9lBOsl7iAt6Z5EH"; String[] candidates = {"admin123","123456","admin","password","root123","12345678","Admin123"}; for (String p : candidates) System.out.println(p + " => " + e.matches(p, hash)); }}
